import{_ as r,o as a,c as o,ai as e}from"./chunks/framework.DMjte4z8.js";const c=JSON.parse('{"title":"新手地图应该多大？地图尺寸选择指南","description":"","frontmatter":{"title":"新手地图应该多大？地图尺寸选择指南","category":"getting-started","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/repositories/maps.564/","https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos","https://classic.battle.net/war3/","https://maps.w3reforged.com/maps/categories","https://www.epicwar.com/maps/help/"]},"headers":[],"relativePath":"getting-started/新手地图应该多大地图尺寸选择指南.md","filePath":"getting-started/新手地图应该多大地图尺寸选择指南.md","lastUpdated":1777383225000}'),s={name:"getting-started/新手地图应该多大地图尺寸选择指南.md"};function n(l,t,i,g,h,d){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="新手地图应该多大-地图尺寸选择指南" tabindex="-1">新手地图应该多大？地图尺寸选择指南 <a class="header-anchor" href="#新手地图应该多大-地图尺寸选择指南" aria-label="Permalink to “新手地图应该多大？地图尺寸选择指南”">​</a></h1><h2 id="为什么地图尺寸对新很重要" tabindex="-1">为什么地图尺寸对新很重要 <a class="header-anchor" href="#为什么地图尺寸对新很重要" aria-label="Permalink to “为什么地图尺寸对新很重要”">​</a></h2><p>在本节中，你将了解地图尺寸如何影响游戏性能和你的开发体验。学完以后，你将能够为自己的第一个RPG地图选择合适的大小，避免后期因为&quot;改不动&quot;而放弃项目。</p><h3 id="地图尺寸与游戏性能的关系" tabindex="-1">地图尺寸与游戏性能的关系 <a class="header-anchor" href="#地图尺寸与游戏性能的关系" aria-label="Permalink to “地图尺寸与游戏性能的关系”">​</a></h3><p>想象一下，地图就像一块画布，画布越大，你需要画的东西就越多。魔兽争霸3在运行地图时，需要同时处理地形、物件、触发器（相当于游戏规则代码）和单位的移动路径[^2]。地图越大，这些内容就越多，对电脑的配置要求也越高。</p><p>对于新手来说，最直接的影响就是：<strong>大地图会让你的触发器运行变慢</strong>。触发器是控制RPG游戏剧情、对话、战斗结算的核心系统。当地图过大时，触发器的检查范围变大，检查频率变高，轻则导致游戏卡顿，重则直接崩溃。</p><h3 id="新手常犯的地图尺寸错误" tabindex="-1">新手常犯的地图尺寸错误 <a class="header-anchor" href="#新手常犯的地图尺寸错误" aria-label="Permalink to “新手常犯的地图尺寸错误”">​</a></h3><ol><li><p><strong>追求&quot;史诗级&quot;大地图</strong> — 很多新手觉得地图越大越厉害，实际上大地图需要填充大量内容才有意义，否则只会显得空旷[^4]。作为新手，你的目标是<strong>先做出一个能玩的完整小游戏</strong>，而不是一个空洞的大世界。</p></li><li><p><strong>选了最大尺寸再缩减</strong> — 很多新手一开始选了最大地图做到一半，发现&quot;hold不住了&quot;再想缩小，这时候前面积累的工作可能全部要调整。</p></li><li><p><strong>边界区域没规划</strong> — 地图边缘如果直接留空白或简单处理，会让玩家觉得&quot;这是一个被截断的世界&quot;。新手往往忽视这一点。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：作为入门练习，建议选择<strong>最小或次小的地图尺寸</strong>。这样你只需要设计几个房间或区域就能填满地图，有更多精力打磨核心玩法（战斗系统、任务流程等）。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手看到官方地图（如DotA、丧尸围城）很大，就想模仿。实际上这些地图经过多年迭代，内容非常丰富。新手直接做大型地图，往往坚持不到完成。建议：<strong>从小开始，做出成品，再考虑扩展</strong>。</p></blockquote><h2 id="warcraft-iii-标准地图尺寸详解" tabindex="-1">Warcraft III 标准地图尺寸详解 <a class="header-anchor" href="#warcraft-iii-标准地图尺寸详解" aria-label="Permalink to “Warcraft III 标准地图尺寸详解”">​</a></h2><p>本节将带你了解 Warcraft III 编辑器中常用的几种标准地图尺寸，以及它们各自的特点。学完本节后，你将能够根据自己地图的类型和用途，挑选出最合适的地图尺寸。</p><h3 id="常见地图尺寸规格一览" tabindex="-1">常见地图尺寸规格一览 <a class="header-anchor" href="#常见地图尺寸规格一览" aria-label="Permalink to “常见地图尺寸规格一览”">​</a></h3><p>在 World Editor（世界编辑器，简称WE，是暴雪自带的地图制作工具）中，地图尺寸以&quot;码&quot;（yard）为单位计算，实际上对应的是编辑器中的<strong>256×256 像素区块</strong>。下面给你列出最常见的几种规格：</p><table tabindex="0"><thead><tr><th>尺寸名称</th><th>实际大小（码）</th><th>适用场景</th></tr></thead><tbody><tr><td>小型</td><td>16×16 或 24×24</td><td>简单塔防、单人剧情</td></tr><tr><td>中型</td><td>32×32 或 48×48</td><td>防守地图、RPG、TD</td></tr><tr><td>大型</td><td>64×64 或 96×96</td><td>Dota类、即时战略</td></tr><tr><td>超大型</td><td>128×128 或更大</td><td>开放世界、自定义战役</td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：地图尺寸的数字越大，代表地图的&quot;画布&quot;越大，你能放进去的内容就越多。但别贪大——新手从 <strong>32×32 或 48×48</strong> 开始最合适。</p></blockquote><h3 id="各尺寸的优缺点对比" tabindex="-1">各尺寸的优缺点对比 <a class="header-anchor" href="#各尺寸的优缺点对比" aria-label="Permalink to “各尺寸的优缺点对比”">​</a></h3><p><strong>小型地图（16×16 ~ 24×24）</strong></p><ul><li>✅ <strong>优点</strong>：加载极快，电脑配置要求低，视野紧凑便于观察全局</li><li>❌ <strong>缺点</strong>：空间有限，很难制作复杂内容，玩家很快就会跑遍全图失去新鲜感</li></ul><p><strong>中型地图（32×32 ~ 48×48）</strong></p><ul><li>✅ <strong>优点</strong>：黄金平衡点！能容纳足够多的触发逻辑（触发器是用来定义游戏规则的脚本）和自定义单位，不会让电脑吃不消[^1]</li><li>❌ <strong>缺点</strong>：如果你想做开放世界冒险，这个尺寸就显得局促了</li></ul><p><strong>大型地图（64×64 以上）</strong></p><ul><li>✅ <strong>优点</strong>：内容丰富，可探索区域大，适合制作类似 Dota 那样的对战地图[^4]</li><li>❌ <strong>缺点</strong>：对玩家的电脑配置要求高；地图越大，编辑器运行时越容易卡顿，新手调试起来会很痛苦</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手以为&quot;地图越大越厉害&quot;，一上来就做 128×128 的超大地图。结果发现编辑器卡得像幻灯片，测试一把要等半分钟加载，还经常崩溃。<strong>建议新手从小尺寸开始熟悉界面，等熟练后再逐步放大。</strong></p></blockquote><h3 id="官方经典地图使用的尺寸" tabindex="-1">官方经典地图使用的尺寸 <a class="header-anchor" href="#官方经典地图使用的尺寸" aria-label="Permalink to “官方经典地图使用的尺寸”">​</a></h3><p>Warcraft III 原版的对战地图（如经典的 1v1、2v2 地图）大多采用 <strong>48×48 到 64×64</strong> 之间的尺寸[^2]。这是经过暴雪反复测试的&quot;黄金区间&quot;，既能保证游戏流畅，又能提供足够的战术空间。</p><p>而大家熟悉的 Dota（全明星对战）地图，则使用了更大的 <strong>96×96</strong> 左右的设计，这样才能容纳十名玩家、多条兵线以及复杂的树林和地形[^4]。如果你想做类似 Dota 的游戏，可以参考这个尺寸。</p><blockquote><p><strong>💡 新手提示</strong>：作为入门，建议先从 <strong>48×48</strong> 入手制作一个简单的防守或 RPG 地图。这个尺寸足够你学习编辑器的基本操作，又不至于让电脑&quot;喘不过气&quot;。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上学习后，你应该已经了解了：</p><ul><li>Warcraft III 编辑器中从 16×16 到 128×128 的各种尺寸规格</li><li>小地图加载快但内容少，大地图内容丰富但对电脑要求高</li><li>原版暴雪地图和 Dota 类地图分别使用了什么尺寸</li></ul><p>下一步，你可以打开 World Editor，尝试创建一个 <strong>48×48</strong> 的空白地图，感受一下不同尺寸在编辑器中呈现的实际大小。记住：<strong>合适比大更重要</strong>！</p><h2 id="根据游戏类型选择地图尺寸" tabindex="-1">根据游戏类型选择地图尺寸 <a class="header-anchor" href="#根据游戏类型选择地图尺寸" aria-label="Permalink to “根据游戏类型选择地图尺寸”">​</a></h2><p>在开始设计地图之前，你需要根据自己计划做的游戏类型来选择合适的地图尺寸。选择对了，后续的开发工作会顺利很多；选错了，可能会导致游戏体验变差或者开发难度大增。</p><h3 id="塔防-防守类地图建议尺寸" tabindex="-1">塔防/防守类地图建议尺寸 <a class="header-anchor" href="#塔防-防守类地图建议尺寸" aria-label="Permalink to “塔防/防守类地图建议尺寸”">​</a></h3><p>塔防地图的尺寸通常建议选择<strong>小到中型</strong>（推荐使用Warcraft III内置的&quot;large&quot;或更小的尺寸）[^4]。</p><p><strong>为什么？</strong> 塔防游戏的核心是玩家在固定位置放置防御建筑，阻挡一波又一波的敌人进攻。如果地图太大，敌人需要走更长的路才能到达终点，这会让游戏节奏变得拖沓；而地图太小又会让玩家没有足够的空间布置防御塔。</p><blockquote><p><strong>💡 新手提示</strong>：塔防地图不需要太大的垂直空间（就是&quot;往上走&quot;的空间），关键是水平方向要有足够长度让敌人走。想象一条长长的赛道，这就是你的基本布局。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易把塔防地图做得太大，结果玩家抱怨游戏太慢，而且你需要写更多的路径点触发器（触发器是让游戏&quot;思考&quot;的代码），工作量翻倍。</p></blockquote><h3 id="角色扮演-rpg地图建议尺寸" tabindex="-1">角色扮演/RPG地图建议尺寸 <a class="header-anchor" href="#角色扮演-rpg地图建议尺寸" aria-label="Permalink to “角色扮演/RPG地图建议尺寸”">​</a></h3><p>RPG地图的大小取决于游戏的设计目标[^2]：</p><table tabindex="0"><thead><tr><th>游戏类型</th><th>推荐尺寸</th><th>原因</th></tr></thead><tbody><tr><td>线性剧情RPG</td><td>中型</td><td>故事从头走到尾，不需要探索大世界</td></tr><tr><td>开放世界RPG</td><td>大型</td><td>需要广阔的地图让玩家自由探索</td></tr><tr><td>副本迷宫RPG</td><td>小到中型</td><td>重点是精心设计的关卡，不是地图面积</td></tr></tbody></table><p><strong>为什么尺寸差异这么大？</strong> 因为RPG游戏的核心是&quot;角色成长&quot;和&quot;故事体验&quot;。如果你的游戏想让玩家像读小说一样跟着剧情走，那就把地图做小一点，重点放在关卡设计和剧情文本上。如果你想让玩家自由探索、到处发现隐藏宝藏，那就需要一个更大的地图。</p><blockquote><p><strong>💡 新手提示</strong>：对于新手来说，建议从<strong>中等尺寸的线性RPG</strong>开始练手。你可以在HIVE等社区下载类似的地图参考[^1]，看看别人是怎么布局的。</p></blockquote><h3 id="对抗-竞技地图建议尺寸" tabindex="-1">对抗/竞技地图建议尺寸 <a class="header-anchor" href="#对抗-竞技地图建议尺寸" aria-label="Permalink to “对抗/竞技地图建议尺寸”">​</a></h3><p>对抗类（玩家vs玩家）或竞技类地图通常选择<strong>小型到中型</strong>，而且对<strong>对称性</strong>要求很高[^4]。</p><p><strong>为什么对称性重要？</strong> 如果地图两边不一样大，地图左边出生的玩家就有天然优势——他们有更大的发展空间，这对右边出生的玩家不公平。在竞技游戏中，公平性是基础。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手做竞技地图时，为了&quot;创意&quot;把地图做成不规则形状，结果玩家们争论不休、投诉不断。建议新手先从<strong>标准的对称布局</strong>开始，等熟练后再尝试创新。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>根据你的游戏类型选择地图尺寸：</p><ul><li><strong>塔防/防守</strong> → 小到中型，横向长条形为主</li><li><strong>RPG/角色扮演</strong> → 根据游戏设计目标选择，线性RPG可用中型，开放世界需要大型</li><li><strong>对抗/竞技</strong> → 小到中型，必须保证两边对称</li></ul><blockquote><p><strong>💡 新手提示</strong>：选好尺寸后，在编辑器中实际建一块测试区域，放几个单位走一走、跑一跑，感受一下这个尺寸&quot;玩起来&quot;是否舒适。有时候数字看着合理，实际体验却是另一回事。</p></blockquote><h2 id="影响地图尺寸选择的因素" tabindex="-1">影响地图尺寸选择的因素 <a class="header-anchor" href="#影响地图尺寸选择的因素" aria-label="Permalink to “影响地图尺寸选择的因素”">​</a></h2><p>在本节中，你将了解哪些因素会影响地图尺寸的选择，并学会根据你的游戏需求确定合适的地图大小。完成学习后，你就能为自己的第一个RPG地图设定合理的尺寸，避免因地图过大或过小而导致的各种问题。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：明确你的玩家人数</strong> — 在设计地图前，先想清楚你的地图支持多少玩家同时游戏。玩家人数是决定地图尺寸的最基本因素[^1]。单人RPG地图和多人对战地图需要的空间完全不同。</p></li><li><p><strong>第二步：根据人数确定基础尺寸</strong> — Warcraft III 编辑器支持创建不同尺寸的地图，较小的尺寸如 32x32 适合1-4名玩家的快节奏游戏，较大的尺寸如 64x64 或 96x96 则适合更多玩家或需要更多探索空间的RPG[^4]。在编辑器中创建新地图时，你可以在地图属性设置中选择这些尺寸。</p></li><li><p><strong>第三步：考虑游戏时长需求</strong> — 地图尺寸还会影响游戏的整体时长。如果你想设计一场30分钟以内的快速战斗，选择较小的地图尺寸可以让玩家更快相遇和战斗[^3]。如果你希望玩家能花1-2小时慢慢探索剧情和寻找隐藏内容，则需要更大的空间来放置任务点和探索区域。</p></li><li><p><strong>第四步：留出合理的留白区域</strong> — 无论选择哪种尺寸，建议在地图边缘预留一些空间作为&quot;边界区&quot;，这样可以避免单位走到地图边缘时出现奇怪的显示问题。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：作为新手，建议从中小型地图开始尝试。太大的地图会让你的触发器和事件系统变得复杂，而且测试时需要花费大量时间步行穿越地图。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手最容易犯的错误是根据自己想象中的&quot;大世界&quot;来设定地图尺寸，结果创建了过大的地图后发现编辑和测试都非常困难。记住，地图尺寸的选择应该服务于游戏玩法，而不是追求视觉效果上的&quot;宏大&quot;。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够根据玩家人数和预计游戏时长来确定自己地图的基础尺寸。记住，作为新手的第一张地图，选择<strong>中小型尺寸</strong>是最稳妥的做法——这样你可以把更多精力放在学习触发器（用来实现游戏逻辑的脚本系统）和单位配置上，而不是被庞大的地图编辑工作量所困扰。一个设计精良的小型地图，远比一个空洞无物的大型地图更能吸引玩家。</p><h2 id="新手推荐-从小型地图开始" tabindex="-1">新手推荐：从小型地图开始 <a class="header-anchor" href="#新手推荐-从小型地图开始" aria-label="Permalink to “新手推荐：从小型地图开始”">​</a></h2><p>在本节中，我将向你解释为什么建议新手从小地图开始创作，以及如何逐步扩大地图规模。读完后，你将能够选择适合自己的入门地图尺寸，并掌握有序扩展地图的方法。</p><h3 id="为什么建议从小尺寸入手" tabindex="-1">为什么建议从小尺寸入手 <a class="header-anchor" href="#为什么建议从小尺寸入手" aria-label="Permalink to “为什么建议从小尺寸入手”">​</a></h3><p>作为新手，强烈建议从小型地图开始创作，原因如下：</p><p>首先，小地图更容易管理地形。在编辑器中移动镜头、放置装饰物、检查边界都很方便，不会因为地图太大而迷失方向[^1]。其次，小地图能大大减少bug出现的概率。地图越大，触发器（控制游戏逻辑的功能）就越复杂，出错的概率也成倍增加。最后，小地图测试速度快，每次修改后能快速验证结果，及时调整方向[^4]。</p><blockquote><p><strong>💡 新手提示</strong>：想象你在拼一幅100块的拼图，对比1000块的拼图。块数少时，你更容易看清整体画面，也更容易找到正确的位置。地图创作也是同样的道理！</p></blockquote><h3 id="推荐的入门地图尺寸" tabindex="-1">推荐的入门地图尺寸 <a class="header-anchor" href="#推荐的入门地图尺寸" aria-label="Permalink to “推荐的入门地图尺寸”">​</a></h3><p>对于刚开始接触地图创作的新手，建议使用以下入门尺寸：</p><p><strong>标准RPG地图</strong>：边长128×128或192×192的游戏单位[^4]。这个尺寸既能容纳一个完整的小型剧情，又不会让地形编辑变得过于繁琐。</p><p><strong>多人合作地图</strong>：可以选择192×192或256×256的尺寸，但仍需控制 playable area（可玩区域）在合理范围内。</p><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会直接复制其他地图的完整尺寸，认为&quot;大地图看起来更专业&quot;。但实际上，尺寸大≠质量高。一张制作精良的小地图远比一张粗糙的大地图更有价值！</p></blockquote><h3 id="如何逐步扩大地图规模" tabindex="-1">如何逐步扩大地图规模 <a class="header-anchor" href="#如何逐步扩大地图规模" aria-label="Permalink to “如何逐步扩大地图规模”">​</a></h3><p>当你的小地图完成度较高、测试无误后，可以按以下步骤逐步扩大：</p><ol><li><strong>第一步：规划扩展方向</strong> — 先想好要在哪个方向增加内容，比如&quot;东边增加一片森林&quot;或&quot;北边添加一座山洞&quot;[^5]</li><li><strong>第二步：选择一块新区域</strong> — 在地图编辑器中，选中一块未使用的区域开始编辑，建议首次扩展不要超过原地图面积的20%</li><li><strong>第三步：测试新区域</strong> — 单独测试新区域的功能，确保没有影响原有内容后再整合测试</li></ol><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该理解了小地图的优势（好管理、少bug、快测试），并记住了推荐的入门尺寸（128×128或192×192）。记住：<strong>从小开始，逐步扩展</strong>，这是大多数成功地图作者的创作之路。现在你可以打开编辑器查看预设模板，开始创作你的第一张小地图了！</p><h2 id="地图尺寸的技术限制与优化" tabindex="-1">地图尺寸的技术限制与优化 <a class="header-anchor" href="#地图尺寸的技术限制与优化" aria-label="Permalink to “地图尺寸的技术限制与优化”">​</a></h2><p>本节将告诉你 Warcraft III 对地图尺寸有哪些硬性限制，以及为什么不能无限制地放大地图。完成学习后，你就能在为地图选择合适尺寸的同时，避免因为超出限制而导致的各种奇怪问题。</p><h3 id="地图尺寸与内存占用" tabindex="-1">地图尺寸与内存占用 <a class="header-anchor" href="#地图尺寸与内存占用" aria-label="Permalink to “地图尺寸与内存占用”">​</a></h3><p>Warcraft III 的地图尺寸使用&quot;码&quot;（Grid）作为单位，你可以在编辑器左上角看到类似 <code>256x256</code> 这样的数字[^2]。这个数字越大，意味着地图的可视面积越大，但同时也意味着游戏需要更多的<strong>内存</strong>来存储地形、物件和单位的数据。</p><blockquote><p><strong>💡 新手提示</strong>：把&quot;内存&quot;想象成一张超大的草稿纸。地图越大，草稿纸就需要越大——但这张纸是有尺寸上限的，超过后游戏就会&quot;写不下&quot;。</p></blockquote><p>Warcraft III 引擎对地图尺寸有以下技术限制：</p><ul><li><strong>最小尺寸</strong>：32x32 码（太小了，几乎做不了什么）</li><li><strong>最大尺寸</strong>：480x480 码（这是硬性上限，无法突破）</li><li><strong>推荐尺寸</strong>：64x64 到 256x256 之间</li></ul><h3 id="超过限制会怎样" tabindex="-1">超过限制会怎样 <a class="header-anchor" href="#超过限制会怎样" aria-label="Permalink to “超过限制会怎样”">​</a></h3><p>新手最常犯的错误是&quot;贪大&quot;，想把地图做得越大越好。实际上，超过技术限制或接近上限会导致严重问题：</p><ol><li><strong>游戏崩溃</strong> — 超过 480x480 码的地图在加载时就会报错，根本无法运行</li><li><strong>严重卡顿</strong> — 即使没超限，地图过大（超过 256x256）也会让游戏变得极卡，因为电脑要在每一帧都计算整个地图</li><li><strong>触发器执行变慢</strong> — 自定义触发器（后面会学到的&quot;小剧本&quot;）需要扫描更多区域，效率大幅下降</li><li><strong>单位寻路出错</strong> — 单位在超大地图上移动时，可能会卡住或走错路</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手觉得&quot;先做个超大地图，以后再精简&quot;，这是错误的做法。超大地图会拖慢你的开发效率，而且精简时需要重新调整所有物件位置，非常麻烦。建议从<strong>64x64</strong>开始练习，熟悉后再逐步放大。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>地图尺寸的选择直接影响游戏性能：</p><ul><li>记住 <strong>480x480 是绝对上限</strong>，不要尝试突破</li><li>优先选择 <strong>64x64 到 256x256</strong> 之间的尺寸</li><li>觉得不够用时，先检查是否真的需要那么大，再考虑是否真的&quot;需要&quot;而非&quot;想要&quot;</li></ul><blockquote><p><strong>🎯 动手试试</strong>：打开你的地图编辑器，查看当前地图尺寸。如果超过 256x256，建议新建一个 128x128 的测试地图来练习。</p></blockquote><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/repositories/maps.564/" target="_blank" rel="noreferrer">Warcraft 3 Custom Maps (multiplayer, campaigns, etc.) | HIVE</a> — accessed 2026-04-28 [^2]: <a href="https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos" target="_blank" rel="noreferrer">Warcraft III: Reign of Chaos - Wikipedia</a> — accessed 2026-04-28 [^3]: <a href="https://classic.battle.net/war3/" target="_blank" rel="noreferrer">Mojo StormStout&#39;s Warcraft III Strategy Guide</a> — accessed 2026-04-28 [^4]: <a href="https://maps.w3reforged.com/maps/categories" target="_blank" rel="noreferrer">211.457 Warcraft III maps in 25 categories</a> — accessed 2026-04-28 [^5]: <a href="https://www.epicwar.com/maps/help/" target="_blank" rel="noreferrer">Warcraft 3 Maps - Epic War.com</a> — accessed 2026-04-28</p>',93)])])}const u=r(s,[["render",n]]);export{c as __pageData,u as default};
